import { useState } from 'react';
import { useDispatch } from 'react-redux';
import { toast } from 'sonner';
import { addGoal } from '@/features/goals/goalsSlice';
import { Modal } from '@/components/ui/modal';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { formatCurrency } from '@/lib/utils';
import { Laptop, Plane, ShieldCheck, Gamepad2, Home as HomeIcon, Car, Smartphone, GraduationCap, Coins, Target } from 'lucide-react';

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#14b8a6', '#f97316'];
const ICONS = [
    { name: 'Laptop', icon: Laptop },
    { name: 'Plane', icon: Plane },
    { name: 'ShieldCheck', icon: ShieldCheck },
    { name: 'Gamepad2', icon: Gamepad2 },
    { name: 'Home', icon: HomeIcon },
    { name: 'Car', icon: Car },
    { name: 'Smartphone', icon: Smartphone },
    { name: 'GraduationCap', icon: GraduationCap },
    { name: 'Coins', icon: Coins },
];

export function CreateGoalModal({ isOpen, onClose }) {
    const dispatch = useDispatch();
    const [name, setName] = useState('');
    const [targetAmount, setTargetAmount] = useState('');
    const [deadline, setDeadline] = useState('');
    const [colorCode, setColorCode] = useState(COLORS[0]);
    const [imageUrl, setImageUrl] = useState(ICONS[0].name);

    const handleCreate = () => {
        if (!name.trim()) {
            toast.error("Vui lòng nhập tên mục tiêu");
            return;
        }

        const numTarget = Number(targetAmount);
        if (!numTarget || numTarget <= 0) {
            toast.error("Số tiền mục tiêu không hợp lệ");
            return;
        }

        if (!deadline) {
            toast.error("Vui lòng chọn hạn chót");
            return;
        }

        const selectedDate = new Date(deadline);
        if (selectedDate <= new Date()) {
            toast.error("Hạn chót phải là một ngày trong tương lai");
            return;
        }

        dispatch(addGoal({
            name: name.trim(),
            targetAmount: numTarget,
            deadline: selectedDate.toISOString(),
            colorCode,
            imageUrl
        }));

        toast.success(`Đã tạo mục tiêu "${name}" thành công!`);

        // Reset and close
        setName('');
        setTargetAmount('');
        setDeadline('');
        setColorCode(COLORS[0]);
        setImageUrl(ICONS[0].name);
        onClose();
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Tạo Mục Tiêu Mới">
            <div className="p-6 space-y-6">

                {/* Visual Preview */}
                <div className="flex items-center justify-center p-6 rounded-xl border border-dashed border-border/60 bg-muted/20">
                    <div className="flex flex-col items-center gap-3">
                        <div
                            className="h-16 w-16 rounded-2xl flex items-center justify-center text-white shadow-md transition-all duration-300"
                            style={{ backgroundColor: colorCode }}
                        >
                            {(() => {
                                const IconComp = ICONS.find(i => i.name === imageUrl)?.icon || Target;
                                return <IconComp className="h-8 w-8" />;
                            })()}
                        </div>
                        <div className="text-center">
                            <h4 className="font-bold text-lg">{name || "Tên Mục Tiêu"}</h4>
                            <p className="text-sm font-medium text-primary">
                                Đích đến: {targetAmount ? formatCurrency(Number(targetAmount)) : '0 ₫'}
                            </p>
                        </div>
                    </div>
                </div>

                {/* Form Fields */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="col-span-full space-y-2">
                        <Label htmlFor="goal-name">Tên Mục Tiêu</Label>
                        <Input
                            id="goal-name"
                            placeholder="Vd: Mua xe máy mới, Đi du lịch..."
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                        />
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="goal-amount">Số Tiền Cần Đạt</Label>
                        <Input
                            id="goal-amount"
                            type="number"
                            placeholder="50000000"
                            value={targetAmount}
                            onChange={(e) => setTargetAmount(e.target.value)}
                        />
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="goal-deadline">Hạn Chót Tích Lũy</Label>
                        <Input
                            id="goal-deadline"
                            type="date"
                            value={deadline}
                            onChange={(e) => setDeadline(e.target.value)}
                        />
                    </div>

                    {/* Color Picker */}
                    <div className="col-span-full space-y-2 pt-2">
                        <Label>Chọn Màu Sắc</Label>
                        <div className="flex flex-wrap gap-3">
                            {COLORS.map(color => (
                                <button
                                    key={color}
                                    type="button"
                                    className={`h-8 w-8 rounded-full shadow-sm border-2 transition-all ${colorCode === color ? 'border-foreground scale-110' : 'border-transparent hover:scale-105'}`}
                                    style={{ backgroundColor: color }}
                                    onClick={() => setColorCode(color)}
                                    title={`Color ${color}`}
                                />
                            ))}
                        </div>
                    </div>

                    {/* Icon Picker */}
                    <div className="col-span-full space-y-2 pt-2">
                        <Label>Chọn Biểu Tượng</Label>
                        <div className="grid grid-cols-5 gap-2 sm:gap-3">
                            {ICONS.map(({ name: iconName, icon: Icon }) => (
                                <button
                                    key={iconName}
                                    type="button"
                                    className={`p-2 flex items-center justify-center rounded-xl border-2 transition-all ${imageUrl === iconName ? 'border-primary bg-primary/10 text-primary' : 'border-border/50 text-muted-foreground hover:bg-muted/50'}`}
                                    onClick={() => setImageUrl(iconName)}
                                >
                                    <Icon className="h-6 w-6" />
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                <div className="pt-4 flex gap-3 justify-end border-t border-border">
                    <Button variant="outline" onClick={onClose}>Hủy Bỏ</Button>
                    <Button onClick={handleCreate}>
                        Tạo Mục Tiêu
                    </Button>
                </div>
            </div>
        </Modal>
    );
}

import { useSelector, useDispatch } from "react-redux"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { formatCurrency } from "@/lib/utils"
import { Clock, Trash2, Power, PowerOff } from "lucide-react"
import { toggleRule, deleteRule } from "@/features/recurring/recurringSlice"

export function RecurringRulesList({ onEdit }) {
    const { rules } = useSelector(state => state.recurring)
    const dispatch = useDispatch()

    const frequencyMap = {
        'DAILY': 'Hàng Ngày',
        'WEEKLY': 'Hàng Tuần',
        'MONTHLY': 'Hàng Tháng',
        'YEARLY': 'Hàng Năm'
    }

    if (rules.length === 0) {
        return (
            <div className="text-center py-10 text-muted-foreground">
                <Clock className="mx-auto h-12 w-12 opacity-20 mb-3" />
                <p>Chưa có lịch định kỳ nào.</p>
                <p className="text-sm">Tạo lịch để tự động hóa các khoản chi thường xuyên.</p>
            </div>
        )
    }

    return (
        <div className="space-y-4">
            {rules.map(rule => (
                <Card key={rule.id} className={rule.active ? "" : "opacity-60 grayscale"}>
                    <CardContent className="p-4 flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className={`flex h-10 w-10 items-center justify-center rounded-full border ${rule.type === 'EXPENSE' ? 'bg-red-50 border-red-100 text-red-600' : 'bg-green-50 border-green-100 text-green-600'}`}>
                                <Clock className="h-5 w-5" />
                            </div>
                            <div>
                                <h3 className="font-semibold flex items-center gap-2">
                                    {rule.name}
                                    {!rule.active && <span className="text-xs bg-muted px-2 py-0.5 rounded text-muted-foreground">Đã tạm dừng</span>}
                                </h3>
                                <p className="text-sm text-muted-foreground">
                                    {formatCurrency(rule.amount)} • {frequencyMap[rule.frequency] || rule.frequency}
                                </p>
                                <p className="text-xs text-muted-foreground">
                                    Đến hạn: {new Date(rule.nextDueDate).toLocaleDateString('vi-VN')}
                                </p>
                            </div>
                        </div>

                        <div className="flex items-center gap-2">
                            <Button
                                variant="ghost"
                                size="icon"
                                onClick={() => dispatch(toggleRule(rule.id))}
                                title={rule.active ? "Tạm dừng" : "Kích hoạt"}
                            >
                                {rule.active ? <Power className="h-4 w-4 text-green-600" /> : <PowerOff className="h-4 w-4 text-muted-foreground" />}
                            </Button>
                            <Button
                                variant="ghost"
                                size="icon"
                                className="text-red-500 hover:text-red-600 hover:bg-red-50"
                                onClick={() => {
                                    if (confirm('Bạn có chắc muốn xóa lịch này không?')) {
                                        dispatch(deleteRule(rule.id))
                                    }
                                }}
                            >
                                <Trash2 className="h-4 w-4" />
                            </Button>
                        </div>
                    </CardContent>
                </Card>
            ))}
        </div>
    )
}

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
    "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
    {
        variants: {
            variant: {
                default:
                    "bg-primary text-primary-foreground shadow hover:bg-primary/90",
                destructive:
                    "bg-destructive text-destructive-foreground shadow-sm hover:bg-destructive/90",
                outline:
                    "border border-input bg-background shadow-sm hover:bg-accent hover:text-accent-foreground",
                secondary:
                    "bg-secondary text-secondary-foreground shadow-sm hover:bg-secondary/80",
                ghost: "hover:bg-accent hover:text-accent-foreground",
                link: "text-primary underline-offset-4 hover:underline",
            },
            size: {
                default: "h-9 px-4 py-2",
                sm: "h-8 rounded-md px-3 text-xs",
                lg: "h-10 rounded-md px-8",
                icon: "h-9 w-9",
            },
        },
        defaultVariants: {
            variant: "default",
            size: "default",
        },
    }
)

const Button = React.forwardRef(({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
        (<Comp
            className={cn(buttonVariants({ variant, size, className }))}
            ref={ref}
            {...props} />)
    );
})
Button.displayName = "Button"

export { Button, buttonVariants }

import { useState } from 'react';
import { useSelector } from 'react-redux';
import { Target, Plus, Laptop, Plane, ShieldCheck, CheckCircle2, TrendingUp, Gamepad2, Home as HomeIcon, Car, Smartphone, GraduationCap, Coins } from 'lucide-react';
import { formatCurrency, formatShortDate } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { DepositModal } from '@/components/features/goals/DepositModal';
import { CreateGoalModal } from '@/components/features/goals/CreateGoalModal';

// Icon Map for dynamic rendering
const iconMap = {
    Laptop: Laptop,
    Plane: Plane,
    ShieldCheck: ShieldCheck,
    Gamepad2: Gamepad2,
    Home: HomeIcon,
    Car: Car,
    Smartphone: Smartphone,
    GraduationCap: GraduationCap,
    Coins: Coins,
};

export function Goals() {
    const { items: goals } = useSelector(state => state.goals);

    // Derived states
    const activeGoals = goals.filter(g => g.status === 'IN_PROGRESS');
    const achievedGoals = goals.filter(g => g.status === 'ACHIEVED');
    const totalTarget = activeGoals.reduce((sum, g) => sum + g.targetAmount, 0);
    const totalSaved = activeGoals.reduce((sum, g) => sum + g.currentAmount, 0);

    // Modal states
    const [selectedGoal, setSelectedGoal] = useState(null);
    const [isDepositModalOpen, setIsDepositModalOpen] = useState(false);
    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);

    const handleOpenDeposit = (goal) => {
        setSelectedGoal(goal);
        setIsDepositModalOpen(true);
    };

    return (
        <div className="space-y-8 animate-in fade-in duration-500">
            {/* Header Area */}
            <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-gradient-to-r from-blue-500/10 to-indigo-500/10 p-6 rounded-3xl border border-primary/20">
                <div className="flex items-center gap-4">
                    <div className="h-16 w-16 bg-primary/20 text-primary rounded-2xl flex items-center justify-center shadow-inner">
                        <Target className="h-8 w-8" />
                    </div>
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight text-foreground">Mục Tiêu Tài Chính</h1>
                        <p className="text-muted-foreground mt-1">Biến ước mơ thành hiện thực thông qua tiết kiệm.</p>
                    </div>
                </div>
                <Button
                    className="w-full sm:w-auto gap-2 shadow-lg hover:shadow-xl transition-all h-11"
                    size="lg"
                    onClick={() => setIsCreateModalOpen(true)}
                >
                    <Plus className="h-5 w-5" /> Tạo Mục Tiêu Mới
                </Button>
            </header>

            {/* Overview Stats */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Card className="bg-card/50 backdrop-blur border-border/50">
                    <CardContent className="p-6 flex items-center justify-between">
                        <div>
                            <p className="text-sm font-medium text-muted-foreground">Tổng đang tích lũy</p>
                            <p className="text-3xl font-bold text-primary mt-1">{formatCurrency(totalSaved)}</p>
                        </div>
                        <div className="h-12 w-12 bg-primary/10 rounded-full flex items-center justify-center text-primary">
                            <TrendingUp className="h-6 w-6" />
                        </div>
                    </CardContent>
                </Card>
                <Card className="bg-card/50 backdrop-blur border-border/50">
                    <CardContent className="p-6 flex items-center justify-between">
                        <div>
                            <p className="text-sm font-medium text-muted-foreground">Mục tiêu đã đạt</p>
                            <p className="text-3xl font-bold text-emerald-500 mt-1">{achievedGoals.length}</p>
                        </div>
                        <div className="h-12 w-12 bg-emerald-500/10 rounded-full flex items-center justify-center text-emerald-500">
                            <CheckCircle2 className="h-6 w-6" />
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Active Goals Grid */}
            <div>
                <h2 className="text-xl font-bold mb-6 flex items-center gap-2">Hũ Đang Mở <span className="bg-secondary text-secondary-foreground text-xs px-2 py-1 rounded-full">{activeGoals.length}</span></h2>
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {activeGoals.map(goal => {
                        const IconComponent = iconMap[goal.imageUrl] || Target;
                        const percentage = Math.min(100, Math.round((goal.currentAmount / goal.targetAmount) * 100));

                        return (
                            <Card key={goal.id} className="overflow-hidden hover:shadow-md transition-shadow group border-border/60">
                                <CardContent className="p-0">
                                    <div className="p-6">
                                        <div className="flex justify-between items-start mb-6">
                                            <div className="flex items-center gap-4">
                                                <div
                                                    className="h-14 w-14 rounded-2xl flex items-center justify-center text-white shadow-sm"
                                                    style={{ backgroundColor: goal.colorCode }}
                                                >
                                                    <IconComponent className="h-7 w-7" />
                                                </div>
                                                <div>
                                                    <h3 className="font-bold text-lg group-hover:text-primary transition-colors">{goal.name}</h3>
                                                    <p className="text-sm text-muted-foreground">Hạn chót: <span className="font-medium text-foreground">{formatShortDate(goal.deadline)}</span></p>
                                                </div>
                                            </div>
                                            <div className="text-right">
                                                <p className="text-xs text-muted-foreground font-medium uppercase tracking-wider mb-1">Cần góp thêm</p>
                                                <p className="text-lg font-bold text-destructive">
                                                    {formatCurrency(goal.targetAmount - goal.currentAmount)}
                                                </p>
                                            </div>
                                        </div>

                                        {/* Progress Bar Area */}
                                        <div className="space-y-2 mb-6">
                                            <div className="flex justify-between text-sm font-medium">
                                                <span className="text-primary">{formatCurrency(goal.currentAmount)}</span>
                                                <span className="text-muted-foreground">{formatCurrency(goal.targetAmount)}</span>
                                            </div>
                                            <div className="h-3 w-full bg-secondary rounded-full overflow-hidden relative">
                                                <div
                                                    className="absolute top-0 left-0 h-full rounded-full transition-all duration-1000 ease-out"
                                                    style={{ width: `${percentage}%`, backgroundColor: goal.colorCode }}
                                                />
                                            </div>
                                            <p className="text-right text-xs font-bold text-muted-foreground">{percentage}%</p>
                                        </div>

                                        <Button
                                            className="w-full text-foreground hover:text-primary-foreground transition-colors font-semibold shadow-sm"
                                            style={{ backgroundColor: `${goal.colorCode}20`, color: goal.colorCode }}
                                            onClick={() => handleOpenDeposit(goal)}
                                        >
                                            Nạp Tiền Vào Hũ
                                        </Button>
                                    </div>
                                </CardContent>
                            </Card>
                        )
                    })}
                </div>
            </div>

            {/* Achieved Goals List */}
            {achievedGoals.length > 0 && (
                <div className="pt-8 opacity-80">
                    <h2 className="text-lg font-bold mb-4 flex items-center gap-2 text-emerald-500">
                        <CheckCircle2 className="h-5 w-5" /> Đã Hoàn Thành
                    </h2>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                        {achievedGoals.map(goal => {
                            const IconComponent = iconMap[goal.imageUrl] || Target;
                            return (
                                <Card key={goal.id} className="bg-emerald-500/5 border-emerald-500/20">
                                    <div className="p-4 flex items-center gap-3">
                                        <div className="h-10 w-10 bg-emerald-500 text-white rounded-lg flex items-center justify-center">
                                            <IconComponent className="h-5 w-5" />
                                        </div>
                                        <div>
                                            <h3 className="font-semibold">{goal.name}</h3>
                                            <p className="text-xs text-emerald-600 font-medium">Đạt {formatCurrency(goal.targetAmount)}</p>
                                        </div>
                                    </div>
                                </Card>
                            )
                        })}
                    </div>
                </div>
            )}

            {/* Modals */}
            {selectedGoal && (
                <DepositModal
                    isOpen={isDepositModalOpen}
                    onClose={() => {
                        setIsDepositModalOpen(false);
                        setSelectedGoal(null);
                    }}
                    goal={selectedGoal}
                />
            )}

            <CreateGoalModal
                isOpen={isCreateModalOpen}
                onClose={() => setIsCreateModalOpen(false)}
            />
        </div>
    );
}
